---@type LFightIdleBaseAction
local LFightIdleBaseAction = LXImport(".LFightIdleBaseAction")

---@class LFightIdleChallengeAction:LFightIdleBaseAction
local LFightIdleChallengeAction = LxClass("LFightIdleChallengeAction", LFightIdleBaseAction)
-----------------------------------------------------------------
function LFightIdleChallengeAction:LFightIdleChallengeAction()
	self._action = LFightIdleConst.ACTION_CHALLENGE

	self._phase = 0 -- 1, 瞬移, 设置镜头， 2 等待攻击, 3 等待 Ns 继续ai


	self._atkTime = 2

	self._waitAiTime = 1

	self._atkIndex = 0
	self._atkNum = 2
	
	self._curBossObj = nil
end

-----------------------------------------------------------------
function LFightIdleChallengeAction:OnRun(time)
	if self._phase == 1 then
		self._phase = 2
		self._atkIndex = 0
		local numFunc = self._manager.GetChallengeHitNum
		if numFunc then
			self._atkNum  = numFunc(self._manager)
			if self._atkNum <= 0 then
				self._atkNum = 1
			end
		end
		if self._curBossObj then
			local objPos = self._obj:GetPosition()
			-- boos 转过来对着我
			self._curBossObj:ChangeDirToPos(objPos)
		end 
		self._obj:GetAtkActor():DoAtk(self._obj:GetCommonSkill():GetExpressId(), 1)
	elseif self._phase == 2 then 
		local actor = self._obj:GetAtkActor()
		if actor:IsAttacking() then
			return
		end
		self._atkIndex = self._atkIndex + 1
		if self._atkIndex >= self._atkNum then
			self._obj:SetTarObjKey(nil)
			self._phase = 3
			self._nextWaitTime = time + self._waitAiTime
			self._manager:AddRunEndEventFunc(function()
				gModelInstance:GotoChallenge()
			end)
		else
			self._obj:GetAtkActor():DoAtk(self._obj:GetCommonSkill():GetExpressId(), 1)
		end
	elseif self._phase == 3 then
		if self._nextWaitTime <= time and self._ai:IsCanChangeAction() then
			self._phase = 0
			self:ResetDefaultAction()
		end
	end
end
-----------------------------------------------------------------
function LFightIdleChallengeAction:ResetDefaultAction()
	if self._obj:SetStatus(LFightIdleConst.STATUS_IDLE) then
		self._obj:PlayIdleAni()
	end
	local ai = self._ai
	ai:ChangeAction(ai:GetDefaultAction())
end

-----------------------------------------------------------------
function LFightIdleChallengeAction:StartAction()
	self._obj:StopActor(true)
	
	local objCtrl = self._manager:GetObjCtrl()
	local missionIdx = objCtrl:GenerateMissionIdx(self._manager:GetBattleNode())
	local missionObj = objCtrl:GetObjByKey(missionIdx)
	local boardRefId = missionObj:GetBoardRefId()
	local areaIndex = missionObj:GetAreaIndex()
	local pathIndex = 1

	local obj = self._obj
	self._curBossObj = missionObj
	-- 开启遮罩显示
	objCtrl:AddMaskObj(obj)
	objCtrl:AddMaskObj(missionObj)
	
	obj:SetTarObjKey(missionIdx)

	obj:SetAreaIndex(areaIndex)
	obj:SetBoardRefId(boardRefId)

	obj:SetPathIndex(pathIndex)

	local boardRef = self._manager:GetBoardRef(boardRefId)
	local paths = boardRef.paths
	local pathData = paths[pathIndex]
	local minPos,maxPos = pathData.left,pathData.right
	obj:SetPathData(minPos,maxPos)

	local missionPos = missionObj:GetPosition()
	local pos = Vector3(missionPos.x,minPos.y,0)
	if pos.x < minPos.x then
		pos.x = minPos.x
	elseif pos.x > maxPos.x then
		pos.x = maxPos.x
	end

	local disL = (pos.x - minPos.x)
	local disR = (maxPos.x - pos.x)

	if disL > disR then
		pos.x = math.max(minPos.x, pos.x - 1)
	else
		pos.x = math.min(maxPos.x, pos.x + 1)
	end

	self._obj:SetPosition(pos)
	self._obj:ChangeDirToPos(missionPos)
	self._obj:PlayIdleAni()
	self._obj:SetStatus(LFightIdleConst.STATUS_CHALLENGE)

	if not missionObj or not (missionObj:IsLive() and missionObj:IsReady()) then
		self._phase = 2
		self._atkIndex = self._atkNum + 1
	else
		self._phase = 1
	end

end

-----------------------------------------------------------------
function LFightIdleChallengeAction:StopAction()
	self._obj:SetTarObjKey(nil)
end

function LFightIdleChallengeAction:Destroy()

	LFightIdleBaseAction.Destroy(self)
end

return LFightIdleChallengeAction